 1→import React from "react";
 2→import { AnimatePresence, motion as Motion } from "framer-motion";
 3→import { BarLoader } from "react-spinners";
 4→
 5→const ProfileFontColorSelector = ({
 6→    show,
 7→    fontColor,
 8→    fontColorInputRef,
 9→    setFontColor,
10→    handleClickInputColor,
11→    handleClickCancelFontSelect,
12→    handleClickSaveFontColor,
13→    isUpdatingFont,
14→}) => {
15→    if (!show) {
16→        return null;
17→    }
18→
19→    return (
20→        <AnimatePresence>
21→            <Motion.div
22→                className="font-selector-container"
23→                initial={{ scale: 0.9, opacity: 0, y: 20 }}
24→                animate={{ scale: 1, opacity: 1, y: 0 }}
25→                exit={{ scale: 0.95, opacity: 0, y: 10 }}
26→                transition={{ type: "spring", stiffness: 250, damping: 25 }}
27→            >
28→                <div
29→                    onClick={() => handleClickInputColor()}
30→                    style={{ background: `${fontColor}` }}
31→                    className="input-color"
32→                ></div>
33→                <div className="font-color-hex-label">{fontColor || "No color"}</div>
34→                <input
35→                    ref={fontColorInputRef}
36→                    value={fontColor}
37→                    onChange={(e) => setFontColor(e.target.value)}
38→                    style={{ display: "none" }}
39→                    type="color"
40→                />
41→                <div className="save-font-color-bttn-container">
42→                    <div className="cancel-button" onClick={() => handleClickCancelFontSelect()}>
43→                        Cancel
44→                    </div>
45→                    <div
46→                        className={`save-button${isUpdatingFont ? " is-saving" : ""}`}
47→                        onClick={() => handleClickSaveFontColor()}
48→                    >
49→                        {isUpdatingFont ? "Saving..." : "Save"}
50→                    </div>
51→                </div>
52→
53→                {isUpdatingFont && (
54→                    <BarLoader
55→                        loading={isUpdatingFont}
56→                        width={"100%"}
57→                        color="var(--accent-purple)"
58→                        speedMultiplier={0.7}
59→                    />
60→                )}
61→            </Motion.div>
62→        </AnimatePresence>
63→    );
64→};
65→
66→export default ProfileFontColorSelector;
