 11→const simpleHash = (str) => {
 12→    let h = 0;
 13→    for(let i = 0; i < str.length; i++){
 14→        h = ((h << 5) - h + str.charCodeAt(i)) | 0;
 15→    }
 16→    return h;
 17→};
